/**
 * Estimate AP management quota fee based on convener fee tier.
 * Pattern from research: Higher convener fee colleges charge more for mgmt quota.
 * CSE/AI branches command 2.5–3x; core branches ~1.5–2x; we use a weighted average.
 */
function estimateAPMgmtFee(convenerFee: number): number {
  if (convenerFee >= 90000) return Math.round(convenerFee * 2.2);   // Top tier
  if (convenerFee >= 70000) return Math.round(convenerFee * 2.0);   // Upper-mid
  if (convenerFee >= 50000) return Math.round(convenerFee * 1.8);   // Mid
  return Math.round(convenerFee * 1.6);                              // Lower
}

/**
 * Generate course list for government or private affiliated colleges.
 * Uses the college's existing B.Tech fee from colleges.ts + standard PG fees from government orders.
 * AP management quota fees: sourced from college websites where available, estimated otherwise.
 */
export function generateAffiliateCourses(c: { code?: string; type: string; state: string; fee: number; goFee: number; branches: string[] }): CourseInfo[] | null {
  if (c.type === "Deemed University" || c.type === "Private University") return null; // use UNIVERSITY_COURSES instead

  const baseFee = c.goFee > 0 ? c.goFee : c.fee;
  const isGovt = c.type === "Government";
  const isAP = c.state === "Andhra Pradesh";
  const isPrivate = c.type === "Private";
  const known = (isAP && isPrivate && c.code) ? AP_KNOWN_MGMT_FEES[c.code] : undefined;

  const hasEngineering = c.branches.some(b => ["CSE","ECE","EEE","MECH","CIVIL","IT","AI&ML","DS","CYS"].includes(b));
  const hasPharmacy = c.branches.includes("B.Pharm");
  const hasPharmD = c.branches.includes("Pharm.D");
  const hasMedical = c.branches.includes("MBBS");

  const courses: CourseInfo[] = [];

  if (hasEngineering) {
    // Engineering fees
    const btechFee = baseFee;
    const mtechFee = isGovt ? (isAP ? 20000 : 25000) : Math.round(btechFee * 0.6);
    const mbaFee = isGovt ? (isAP ? 25000 : 30000) : (isAP ? 55000 : 80000);
    const mcaFee = isGovt ? (isAP ? 20000 : 25000) : (isAP ? 40000 : 55000);

    // Management quota fees — use known data, then AP-specific estimate, then generic multiplier
    const btechMgmt = isPrivate
      ? (known?.btech ?? (isAP ? estimateAPMgmtFee(btechFee) : Math.round(btechFee * 2)))
      : undefined;
    const mbaMgmt = isPrivate
      ? (known?.mba ?? (isAP ? Math.round(mbaFee * 2) : Math.round(mbaFee * 2)))
      : undefined;
    const mcaMgmt = isPrivate
      ? (known?.mca ?? (isAP ? Math.round(mcaFee * 1.8) : Math.round(mcaFee * 2)))
      : undefined;
    const mtechMgmt = isPrivate
      ? (known?.mtech ?? (isAP ? Math.round(mtechFee * 1.8) : Math.round(mtechFee * 2)))
      : undefined;

    courses.push({ program: "B.Tech", specialization: isGovt ? "All Branches" : "All Branches (Convener Quota)", fee: btechFee, ...(btechMgmt ? { mgmtFee: btechMgmt } : {}), duration: 4, level: "UG" });
    courses.push({ program: "M.Tech", fee: mtechFee, ...(mtechMgmt ? { mgmtFee: mtechMgmt } : {}), duration: 2, level: "PG" });

    if (btechFee >= 50000) {
      courses.push({ program: "MBA", specialization: isGovt ? undefined : "Convener Quota", fee: mbaFee, ...(mbaMgmt ? { mgmtFee: mbaMgmt } : {}), duration: 2, level: "PG" });
      courses.push({ program: "MCA", specialization: isGovt ? undefined : "Convener Quota", fee: mcaFee, ...(mcaMgmt ? { mgmtFee: mcaMgmt } : {}), duration: 2, level: "PG" });
    }
  }

  if (hasPharmacy) {
    // B.Pharm fees — APHERMC/TAFRC regulated
    const bpharmFee = hasEngineering ? (isAP ? 45000 : 50000) : baseFee;
    const mpharmFee = isGovt ? (isAP ? 20000 : 25000) : Math.round(bpharmFee * 0.7);
    const bpharmMgmt = isPrivate
      ? (known?.bpharm ?? (isAP ? Math.round(bpharmFee * 2) : Math.round(bpharmFee * 2)))
      : undefined;
    const mpharmMgmt = isPrivate
      ? (known?.mpharm ?? (isAP ? Math.round(mpharmFee * 2) : Math.round(mpharmFee * 2)))
      : undefined;

    courses.push({ program: "B.Pharm", fee: bpharmFee, ...(bpharmMgmt ? { mgmtFee: bpharmMgmt } : {}), duration: 4, level: "UG" });
    courses.push({ program: "M.Pharm", fee: mpharmFee, ...(mpharmMgmt ? { mgmtFee: mpharmMgmt } : {}), duration: 2, level: "PG" });
  }

  if (hasPharmD) {
    const pharmdFee = hasEngineering ? (isAP ? 68000 : 75000) : Math.round(baseFee * 1.3);
    const pharmdMgmt = isPrivate ? (isAP ? Math.round(pharmdFee * 2) : Math.round(pharmdFee * 2)) : undefined;
    courses.push({ program: "Pharm.D", fee: pharmdFee, ...(pharmdMgmt ? { mgmtFee: pharmdMgmt } : {}), duration: 6, level: "Integrated" });
  }

  if (hasMedical) {
    // MBBS fees — state government regulated; mgmt quota ~₹12–13L for AP private medical
    const mbbsFee = baseFee;
    const mbbsMgmt = isPrivate ? (isAP ? 1300000 : Math.round(mbbsFee * 1.5)) : undefined;
    courses.push({ program: "MBBS", fee: mbbsFee, ...(mbbsMgmt ? { mgmtFee: mbbsMgmt } : {}), duration: 5, level: "UG" });
    if (mbbsFee > 0) {
      const mdFee = isGovt ? (isAP ? 50000 : 60000) : Math.round(mbbsFee * 1.2);
      courses.push({ program: "MD/MS", fee: mdFee, duration: 3, level: "PG" });
    }
  }

  return courses.length > 0 ? courses : null;
}

/** Get courses for any college */
export function getCourses(code: string): CourseInfo[] | null {
  return UNIVERSITY_COURSES[code] || null;
}

/** Get courses for affiliated colleges (generated from fee data) */
export function getAffiliatedCourses(c: { code?: string; type: string; state: string; fee: number; goFee: number; branches: string[] }): CourseInfo[] | null {
  return generateAffiliateCourses(c);
}

/** Format fee */
export const fmtCourseFee = (fee: number): string => {
  return `₹${fee.toLocaleString("en-IN")}`;
};
